        class PriorityQueue<T> {
            private heap: { priority: number; value: T }[] = [];
            push(value: T, priority: number) {
                this.heap.push({ priority, value });
                this.bubbleUp();
            }
            pop(): T | undefined {
                if (this.size() === 0) return undefined;
                const top = this.heap[0].value;
                const bottom = this.heap.pop()!;
                if (this.size() > 0) {
                    this.heap[0] = bottom;
