        export function aStarGridShortestPath(grid: number[][], start: readonly [number, number], end: readonly [number, number]): number | null {
            const rows = grid.length;
            if (rows === 0) return null;
            const cols = grid[0].length;
            const [startRow, startCol] = start;
            const [endRow, endCol] = end;

            if (startRow < 0 || startRow >= rows || startCol < 0 || startCol >= cols ||
                endRow < 0 || endRow >= rows || endCol < 0 || endCol >= cols ||
                grid[startRow][startCol] === 1 || grid[endRow][endCol] === 1) {
                return null;
            }

            const dist = Array.from({ length: rows }, () => Array(cols).fill(Infinity));
            const pq = new PriorityQueue<{ r: number; c: number; g: number }>();

            dist[startRow][startCol] = 0;
            pq.push({ r: startRow, c: startCol, g: 0 }, Math.abs(startRow - endRow) + Math.abs(startCol - endCol));

            const dr = [0, 0, 1, -1];
            const dc = [1, -1, 0, 0];

            while (pq.size() > 0) {
                const curr = pq.pop()!;
                const { r, c, g } = curr;

                if (r === endRow && c === endCol) return g;
                if (g > dist[r][c]) continue;

                for (let i = 0; i < 4; i++) {
                    const nr = r + dr[i];
                    const nc = c + dc[i];

                    if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc] === 0) {
                        const newG = g + 1;
                        if (newG < dist[nr][nc]) {
                            dist[nr][nc] = newG;
                            pq.push({ r: nr, c: nc, g: newG }, newG + Math.abs(nr - endRow) + Math.abs(nc - endCol));
                        }
                    }
                }
            }

            return null;
        }
