export function integerBreakMaxProduct(n: number): number {
	if (n <= 3) return n - 1;
	let product = 1;
	while (n > 4) {
		product *= 3;
		n -= 3;
	}
	return product * n;
}

export function longestCommonSubsequence(a: string, b: string): number {
	const m = a.length;
	const n = b.length;
	const dp: number[][] = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));

	for (let i = 1; i <= m; i++) {
		for (let j = 1; j <= n; j++) {
			if (a[i - 1] === b[j - 1]) {
				dp[i][j] = dp[i - 1][j - 1] + 1;
			} else {
				dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
			}
		}
	}

	return dp[m][n];
}

