type ListNode = { value: number; next: ListNode | null };

export function mergeSortLinkedList(head: ListNode | null): ListNode | null {
	if (!head || !head.next) {
		return head;
	}

	let slow: ListNode = head;
	let fast: ListNode = head;

	while (fast.next && fast.next.next) {
		slow = slow.next!;
		fast = fast.next.next;
	}

	const mid = slow;
	const nextToMid = slow.next;
	mid.next = null;

	const left = mergeSortLinkedList(head);
	const right = mergeSortLinkedList(nextToMid);

	return merge(left, right);
}

function merge(l1: ListNode | null, l2: ListNode | null): ListNode | null {
	const dummy: ListNode = { value: 0, next: null };
	let current = dummy;

	while (l1 && l2) {
		if (l1.value < l2.value) {
			current.next = l1;
			l1 = l1.next;
		} else {
			current.next = l2;
			l2 = l2.next;
		}
		current = current.next;
	}

	current.next = l1 || l2;

	return dummy.next;
}

