export function minStack(operations: readonly (readonly ['push' | 'pop' | 'top' | 'getMin', number?])[]): (number | null)[] {
	const stack: number[] = [];
	const minStack: number[] = [];
	const results: (number | null)[] = [];

	for (const [op, val] of operations) {
		if (op === 'push') {
			if (val !== undefined) {
				stack.push(val);
				if (minStack.length === 0 || val <= minStack[minStack.length - 1]) {
					minStack.push(val);
				}
			}
		} else if (op === 'pop') {
			const popped = stack.pop();
			if (popped !== undefined && popped === minStack[minStack.length - 1]) {
				minStack.pop();
			}
			results.push(popped ?? null);
		} else if (op === 'top') {
			results.push(stack[stack.length - 1] ?? null);
		} else if (op === 'getMin') {
			results.push(minStack[minStack.length - 1] ?? null);
		}
	}

	return results;
}

