.card {
	display: flex;
	flex-direction: column;
	border: 1px solid #d7dbe2;
	border-radius: 0.75rem;
	background: #ffffff;
	overflow: hidden;
	transition: transform 180ms ease, box-shadow 180ms ease;
}

.card__image {
	aspect-ratio: 4 / 3;
	overflow: hidden;
	background: #eef2f7;
}

.card__image img {
	width: 100%;
	height: 100%;
	object-fit: cover;
	display: block;
}

.card__body {
	padding: 1rem;
	display: grid;
	gap: 0.5rem;
}

.card__footer {
	padding: 0.75rem 1rem 1rem;
	margin-top: auto;
	display: flex;
	align-items: center;
	justify-content: space-between;
	gap: 0.5rem;
}

.card:is(:hover, :focus-within) {
	transform: translateY(-4px);
	box-shadow: 0 10px 24px rgb(8 20 38 / 0.18);
}

.card__primary-link:focus-visible {
	outline: 3px solid #0d8a5e;
	outline-offset: 2px;
	border-radius: 0.25rem;
}

@keyframes shimmer {
	0% {
		background-position: 200% 0;
	}

	100% {
		background-position: -200% 0;
	}
}

.card.is-loading .card__image,
.card.is-loading .card__line,
.card.is-loading .card__chip {
	color: transparent;
	background: linear-gradient(100deg, #edf1f7 25%, #dfe6f0 37%, #edf1f7 63%);
	background-size: 300% 100%;
	animation: shimmer 1.2s ease-in-out infinite;
	border-radius: 0.375rem;
}

