export function bloomFilterNHashFunctions(size: number, hashCount: number, wordsToAdd: string[], queries: string[]): boolean[] {
	const bitArray = new Uint8Array(size);

	const getHash = (s: string, seed: number, m: number): number => {
		let h = seed;
		for (let i = 0; i < s.length; i++) {
			h = Math.imul(h ^ s.charCodeAt(i), 0x5bd1e995);
			h ^= h >>> 15;
		}
		return (h >>> 0) % m;
	};

	for (const word of wordsToAdd) {
		for (let i = 0; i < hashCount; i++) {
			bitArray[getHash(word, i, size)] = 1;
		}
	}

	const results: boolean[] = [];
	for (const query of queries) {
		let present = true;
		for (let i = 0; i < hashCount; i++) {
			if (bitArray[getHash(query, i, size)] === 0) {
				present = false;
				break;
			}
		}
		results.push(present);
	}

	return results;
}

