export function reverseLinkedListInPlace(head: {value: number; next: any} | null): {value: number; next: any} | null {
	let prev = null;
	let current = head;
	while (current !== null) {
		let next = current.next;
		current.next = prev;
		prev = current;
		current = next;
	}
	return prev;
}

