export function trieAutocomplete(words: string[], prefixes: string[]): string[][] {
	class TrieNode {
		children: { [key: string]: TrieNode } = {};
		isEndOfWord: boolean = false;
	}

	class Trie {
		root: TrieNode = new TrieNode();

		insert(word: string): void {
			let node = this.root;
			for (const char of word) {
				if (!node.children[char]) {
					node.children[char] = new TrieNode();
				}
				node = node.children[char];
			}
			node.isEndOfWord = true;
		}

		findPrefixNode(prefix: string): TrieNode | null {
			let node = this.root;
			for (const char of prefix) {
				if (!node.children[char]) {
					return null;
				}
				node = node.children[char];
			}
			return node;
		}

		collectWords(node: TrieNode, currentWord: string, results: string[]): void {
			if (node.isEndOfWord) {
				results.push(currentWord);
			}

			const sortedChars = Object.keys(node.children).sort();
			for (const char of sortedChars) {
				this.collectWords(node.children[char], currentWord + char, results);
			}
		}

		autocomplete(prefix: string): string[] {
			const node = this.findPrefixNode(prefix);
			if (!node) {
				return [];
			}
			const results: string[] = [];
			this.collectWords(node, prefix, results);
			return results;
		}
	}

	const trie = new Trie();
	for (const word of words) {
		trie.insert(word);
	}

	return prefixes.map(prefix => trie.autocomplete(prefix));
}

