export function validateBinarySearchTree(root: {value: number; left: any; right: any} | null): boolean {
	function validate(node: any, min: number, max: number): boolean {
		if (node === null) {
			return true;
		}
		if (node.value <= min || node.value >= max) {
			return false;
		}
		return validate(node.left, min, node.value) && validate(node.right, node.value, max);
	}
	return validate(root, -Infinity, Infinity);
}

export function validateDate(s: string): boolean {
	if (!/^\d{4}-\d{2}-\d{2}$/.test(s)) {
		return false;
	}

	const [yearStr, monthStr, dayStr] = s.split('-');
	const year = parseInt(yearStr, 10);
	const month = parseInt(monthStr, 10);
	const day = parseInt(dayStr, 10);

	if (month < 1 || month > 12) {
		return false;
	}

	const daysInMonth = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];

	if (month === 2) {
		const isLeap = (year % 4 === 0 && year % 100 !== 0) || (year % 400 === 0);
		if (isLeap) {
			daysInMonth[1] = 29;
		}
	}

	return day >= 1 && day <= daysInMonth[month - 1];
}

